import json
import sys

def resolve_roles(user_roles, hierarchy):
    """Resolve all effective roles including inherited ones."""
    effective = set(user_roles)
    queue = list(user_roles)
    while queue:
        role = queue.pop(0)
        for inherited in hierarchy.get(role, []):
            if inherited not in effective:
                effective.add(inherited)
                queue.append(inherited)
    return effective

def check_permission(effective_roles, role_permissions, resource, action):
    """Check if any effective role grants the requested permission."""
    for role in effective_roles:
        for perm in role_permissions.get(role, []):
            if perm['resource'] == resource and action in perm['actions']:
                return True, role
    return False, None

def find_inheritance_path(user_roles, hierarchy, target_role):
    """Find the inheritance path to the target role."""
    if target_role in user_roles:
        return f"direct permission on {target_role} role"
    for role in user_roles:
        path = [role]
        queue = [(role, path)]
        visited = set()
        while queue:
            current, current_path = queue.pop(0)
            if current in visited:
                continue
            visited.add(current)
            for inherited in hierarchy.get(current, []):
                new_path = current_path + [inherited]
                if inherited == target_role:
                    return f"inherited from {target_role} via {' via '.join(reversed(current_path))}"
                queue.append((inherited, new_path))
    return f"direct permission on {target_role} role"

def access_decision_engine(data):
    """Process access requests and return decisions."""
    hierarchy = data['roles_hierarchy']
    role_permissions = data['role_permissions']
    requests = data['access_requests']

    decisions = []
    for req in requests:
        user = req['user']
        user_roles = req['roles']
        resource = req['resource']
        action = req['action']

        effective_roles = resolve_roles(user_roles, hierarchy)
        granted, granting_role = check_permission(effective_roles, role_permissions, resource, action)

        if granted:
            reason = find_inheritance_path(user_roles, hierarchy, granting_role)
            decisions.append({
                'user': user, 'resource': resource, 'action': action,
                'decision': 'ALLOW', 'reason': reason
            })
        else:
            role_str = '/'.join(user_roles)
            decisions.append({
                'user': user, 'resource': resource, 'action': action,
                'decision': 'DENY',
                'reason': f"{role_str} role has no {action} permission on {resource}"
            })

    allowed = sum(1 for d in decisions if d['decision'] == 'ALLOW')
    denied = sum(1 for d in decisions if d['decision'] == 'DENY')

    return json.dumps({
        'decisions': decisions,
        'summary': {'total_requests': len(requests), 'allowed': allowed, 'denied': denied}
    }, indent=2)

data = json.loads(sys.stdin.read())
print(access_decision_engine(data))
